const request = require('supertest');
const { db } = require('../../src/config/database');
const { v4: uuidv4 } = require('uuid');

// 创建测试应用实例
const express = require('express');
const app = express();
app.use(express.json());

// 模拟认证中间件
const mockAuth = (req, res, next) => {
  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Bearer test-token-')) {
    const userId = authHeader.replace('Bearer test-token-', '');
    req.user = { id: userId };
    next();
  } else {
    res.status(401).json({ success: false, error: '认证失败' });
  }
};

// 模拟商店路由
app.use('/api/store', mockAuth, (req, res) => {
  if (req.method === 'GET' && req.path === '/items') {
    res.json({
      success: true,
      data: [
        {
          id: 'item_1',
          name: '像素加速器',
          type: 'pixel_boost',
          price_points: 100
        },
        {
          id: 'item_2',
          name: '联盟旗帜图案',
          type: 'pattern',
          price_points: 200
        }
      ]
    });
  } else if (req.method === 'POST' && req.path === '/purchase') {
    const { itemId, quantity, paymentMethod } = req.body;
    
    if (paymentMethod === 'points') {
      res.json({
        success: true,
        data: {
          transaction: { id: uuidv4() }
        }
      });
    } else {
      const orderId = `order_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
      res.json({
        success: true,
        data: {
          orderId,
          qrCode: `data:image/png;base64,test-qr-${orderId}`,
          status: 'pending'
        }
      });
    }
  } else if (req.method === 'GET' && req.path === '/points') {
    res.json({
      success: true,
      data: { points: 2000 }
    });
  } else if (req.method === 'GET' && req.path === '/inventory') {
    res.json({
      success: true,
      data: [
        {
          item_id: 'item_1',
          quantity: 1,
          consumed: false
        }
      ]
    });
  } else if (req.method === 'POST' && req.path === '/use') {
    res.json({
      success: true,
      data: {
        effects: { pixel_points: 50 }
      }
    });
  } else if (req.method === 'GET' && req.path === '/flag-patterns') {
    res.json({
      success: true,
      data: ['item_2']
    });
  } else if (req.method === 'GET' && req.path === '/cosmetics') {
    res.json({
      success: true,
      data: []
    });
  }
});

// 模拟支付回调路由
app.post('/api/payment/callback/:method', (req, res) => {
  const { method } = req.params;
  const { orderId, status, transactionId } = req.body;
  
  res.json({
    success: true,
    data: {
      orderId,
      status: status === 'success' ? 'completed' : 'failed'
    }
  });
});

describe('Complete User Flow E2E Tests', () => {
  let testUser;
  let testItems = [];
  let authToken;

  beforeAll(async () => {
    // 创建测试用户
    testUser = {
      id: uuidv4(),
      username: 'e2etestuser',
      email: 'e2etest@example.com',
      points: 2000
    };

    // 创建不同类型的测试商品
    const itemTypes = [
      { type: 'pixel_boost', name: '像素加速器', price: 100 },
      { type: 'pattern', name: '联盟旗帜图案', price: 200 },
      { type: 'frame', name: '头像框', price: 150 },
      { type: 'bubble', name: '聊天气泡', price: 120 },
      { type: 'badge', name: '成就徽章', price: 80 },
      { type: 'bomb', name: '炸弹道具', price: 300 },
      { type: 'ad', name: '广告额度', price: 500 }
    ];

    testItems = itemTypes.map((itemType, index) => ({
      id: uuidv4(),
      name: itemType.name,
      type: itemType.type,
      price_points: itemType.price,
      active: true,
      metadata: {
        description: `测试${itemType.name}`,
        icon: `🎯${index}`
      }
    }));

    // 插入测试数据
    await db('users').insert(testUser);
    await db('store_items').insert(testItems);
  });

  afterAll(async () => {
    // 清理测试数据
    await db('users').where('id', testUser.id).del();
    await db('store_items').whereIn('id', testItems.map(i => i.id)).del();
    await db.destroy();
  });

  describe('Complete Store Purchase Flow', () => {
    it('should complete full purchase flow with points', async () => {
      // 1. 浏览商店商品
      const itemsResponse = await request(app)
        .get('/api/store/items')
        .expect(200);

      expect(itemsResponse.body.success).toBe(true);
      expect(itemsResponse.body.data.length).toBeGreaterThan(0);

      // 2. 查看用户积分
      const pointsResponse = await request(app)
        .get('/api/store/points')
        .set('Authorization', `Bearer test-token-${testUser.id}`)
        .expect(200);

      const initialPoints = pointsResponse.body.data.points;
      expect(initialPoints).toBe(2000);

      // 3. 购买像素加速器
      const pixelBoostItem = testItems.find(item => item.type === 'pixel_boost');
      const purchaseResponse = await request(app)
        .post('/api/store/purchase')
        .set('Authorization', `Bearer test-token-${testUser.id}`)
        .set('X-Idempotency-Key', uuidv4())
        .send({
          itemId: pixelBoostItem.id,
          quantity: 1,
          paymentMethod: 'points'
        })
        .expect(200);

      expect(purchaseResponse.body.success).toBe(true);
      expect(purchaseResponse.body.data).toHaveProperty('transaction');

      // 4. 验证积分扣减
      const updatedPointsResponse = await request(app)
        .get('/api/store/points')
        .set('Authorization', `Bearer test-token-${testUser.id}`)
        .expect(200);

      const updatedPoints = updatedPointsResponse.body.data.points;
      expect(updatedPoints).toBe(initialPoints - pixelBoostItem.price_points);

      // 5. 验证商品入库
      const inventoryResponse = await request(app)
        .get('/api/store/inventory')
        .set('Authorization', `Bearer test-token-${testUser.id}`)
        .expect(200);

      const purchasedItem = inventoryResponse.body.data.find(
        item => item.item_id === pixelBoostItem.id
      );
      expect(purchasedItem).toBeDefined();
      expect(purchasedItem.quantity).toBe(1);
      expect(purchasedItem.consumed).toBe(false);
    });

    it('should complete purchase flow with external payment', async () => {
      // 1. 购买需要外部支付的商品（广告额度）
      const adItem = testItems.find(item => item.type === 'ad');
      
      const purchaseResponse = await request(app)
        .post('/api/store/purchase')
        .set('Authorization', `Bearer test-token-${testUser.id}`)
        .set('X-Idempotency-Key', uuidv4())
        .send({
          itemId: adItem.id,
          quantity: 1,
          paymentMethod: 'wechat'
        })
        .expect(200);

      expect(purchaseResponse.body.success).toBe(true);
      expect(purchaseResponse.body.data).toHaveProperty('orderId');
      expect(purchaseResponse.body.data).toHaveProperty('qrCode');

      const orderId = purchaseResponse.body.data.orderId;

      // 2. 模拟支付成功回调
      const callbackResponse = await request(app)
        .post('/api/payment/callback/wechat')
        .send({
          orderId: orderId,
          status: 'success',
          transactionId: uuidv4()
        })
        .expect(200);

      expect(callbackResponse.body.success).toBe(true);

      // 3. 验证商品入库
      const inventoryResponse = await request(app)
        .get('/api/store/inventory')
        .set('Authorization', `Bearer test-token-${testUser.id}`)
        .expect(200);

      const purchasedItem = inventoryResponse.body.data.find(
        item => item.item_id === adItem.id
      );
      expect(purchasedItem).toBeDefined();
      expect(purchasedItem.quantity).toBe(1);
    });
  });

  describe('Item Usage Flow', () => {
    it('should use pixel boost item successfully', async () => {
      // 1. 确保有像素加速器
      const pixelBoostItem = testItems.find(item => item.type === 'pixel_boost');
      
      // 如果没有，先购买一个
      const inventoryResponse = await request(app)
        .get('/api/store/inventory')
        .set('Authorization', `Bearer test-token-${testUser.id}`);

      let pixelBoostInInventory = inventoryResponse.body.data.find(
        item => item.item_id === pixelBoostItem.id
      );

      if (!pixelBoostInInventory || pixelBoostInInventory.quantity === 0) {
        await request(app)
          .post('/api/store/purchase')
          .set('Authorization', `Bearer test-token-${testUser.id}`)
          .set('X-Idempotency-Key', uuidv4())
          .send({
            itemId: pixelBoostItem.id,
            quantity: 1,
            paymentMethod: 'points'
          });
      }

      // 2. 使用像素加速器
      const useResponse = await request(app)
        .post('/api/store/use')
        .set('Authorization', `Bearer test-token-${testUser.id}`)
        .send({
          itemId: pixelBoostItem.id,
          quantity: 1
        })
        .expect(200);

      expect(useResponse.body.success).toBe(true);
      expect(useResponse.body.data).toHaveProperty('effects');

      // 3. 验证库存减少
      const updatedInventoryResponse = await request(app)
        .get('/api/store/inventory')
        .set('Authorization', `Bearer test-token-${testUser.id}`);

      const updatedPixelBoost = updatedInventoryResponse.body.data.find(
        item => item.item_id === pixelBoostItem.id
      );
      expect(updatedPixelBoost.quantity).toBe(0);
      expect(updatedPixelBoost.consumed).toBe(true);
    });

    it('should use pattern item for alliance flag', async () => {
      // 1. 购买图案
      const patternItem = testItems.find(item => item.type === 'pattern');
      
      await request(app)
        .post('/api/store/purchase')
        .set('Authorization', `Bearer test-token-${testUser.id}`)
        .set('X-Idempotency-Key', uuidv4())
        .send({
          itemId: patternItem.id,
          quantity: 1,
          paymentMethod: 'points'
        });

      // 2. 获取用户拥有的旗帜图案
      const flagPatternsResponse = await request(app)
        .get('/api/store/flag-patterns')
        .set('Authorization', `Bearer test-token-${testUser.id}`)
        .expect(200);

      expect(flagPatternsResponse.body.success).toBe(true);
      expect(flagPatternsResponse.body.data).toContain(patternItem.id);
    });

    it('should use cosmetic items for profile', async () => {
      // 1. 购买头像框
      const frameItem = testItems.find(item => item.type === 'frame');
      
      await request(app)
        .post('/api/store/purchase')
        .set('Authorization', `Bearer test-token-${testUser.id}`)
        .set('X-Idempotency-Key', uuidv4())
        .send({
          itemId: frameItem.id,
          quantity: 1,
          paymentMethod: 'points'
        });

      // 2. 获取用户拥有的装饰品
      const cosmeticsResponse = await request(app)
        .get('/api/store/cosmetics')
        .set('Authorization', `Bearer test-token-${testUser.id}`)
        .expect(200);

      expect(cosmeticsResponse.body.success).toBe(true);
      expect(cosmeticsResponse.body.data).toContain(frameItem.id);
    });
  });

  describe('Error Handling in User Flow', () => {
    it('should handle insufficient points gracefully', async () => {
      // 设置用户积分为0
      await db('users').where('id', testUser.id).update({ points: 0 });

      const item = testItems[0];
      
      const response = await request(app)
        .post('/api/store/purchase')
        .set('Authorization', `Bearer test-token-${testUser.id}`)
        .set('X-Idempotency-Key', uuidv4())
        .send({
          itemId: item.id,
          quantity: 1,
          paymentMethod: 'points'
        })
        .expect(400);

      expect(response.body.success).toBe(false);
      expect(response.body.error).toContain('积分不足');
    });

    it('should handle using non-existent item', async () => {
      const response = await request(app)
        .post('/api/store/use')
        .set('Authorization', `Bearer test-token-${testUser.id}`)
        .send({
          itemId: 'non-existent-item-id',
          quantity: 1
        })
        .expect(400);

      expect(response.body.success).toBe(false);
      expect(response.body.error).toContain('商品不存在');
    });

    it('should handle using item without inventory', async () => {
      const item = testItems.find(item => item.type === 'bomb');
      
      const response = await request(app)
        .post('/api/store/use')
        .set('Authorization', `Bearer test-token-${testUser.id}`)
        .send({
          itemId: item.id,
          quantity: 1
        })
        .expect(400);

      expect(response.body.success).toBe(false);
      expect(response.body.error).toContain('库存不足');
    });
  });

  describe('Mobile Experience Tests', () => {
    it('should handle rapid touch interactions', async () => {
      const item = testItems.find(item => item.type === 'pixel_boost');
      
      // 模拟快速点击购买按钮
      const promises = Array(3).fill().map(() => {
        const idempotencyKey = uuidv4();
        return request(app)
          .post('/api/store/purchase')
          .set('Authorization', `Bearer test-token-${testUser.id}`)
          .set('X-Idempotency-Key', idempotencyKey)
          .send({
            itemId: item.id,
            quantity: 1,
            paymentMethod: 'points'
          });
      });

      const responses = await Promise.all(promises);

      // 所有请求都应该成功
      responses.forEach(response => {
        expect(response.status).toBe(200);
        expect(response.body.success).toBe(true);
      });
    });

    it('should handle network interruption gracefully', async () => {
      const item = testItems[0];
      
      // 模拟网络中断（使用无效的认证token）
      const response = await request(app)
        .post('/api/store/purchase')
        .set('Authorization', 'Bearer invalid-token')
        .set('X-Idempotency-Key', uuidv4())
        .send({
          itemId: item.id,
          quantity: 1,
          paymentMethod: 'points'
        })
        .expect(401);

      expect(response.body.success).toBe(false);
    });
  });

  describe('Data Consistency Tests', () => {
    it('should maintain data consistency across multiple operations', async () => {
      // 1. 记录初始状态
      const initialPointsResponse = await request(app)
        .get('/api/store/points')
        .set('Authorization', `Bearer test-token-${testUser.id}`);

      const initialPoints = initialPointsResponse.body.data.points;
      const initialInventoryResponse = await request(app)
        .get('/api/store/inventory')
        .set('Authorization', `Bearer test-token-${testUser.id}`);

      const initialInventoryCount = initialInventoryResponse.body.data.length;

      // 2. 执行多个操作
      const item = testItems.find(item => item.type === 'pixel_boost');
      
      // 购买
      await request(app)
        .post('/api/store/purchase')
        .set('Authorization', `Bearer test-token-${testUser.id}`)
        .set('X-Idempotency-Key', uuidv4())
        .send({
          itemId: item.id,
          quantity: 1,
          paymentMethod: 'points'
        });

      // 使用
      await request(app)
        .post('/api/store/use')
        .set('Authorization', `Bearer test-token-${testUser.id}`)
        .send({
          itemId: item.id,
          quantity: 1
        });

      // 3. 验证最终状态
      const finalPointsResponse = await request(app)
        .get('/api/store/points')
        .set('Authorization', `Bearer test-token-${testUser.id}`);

      const finalPoints = finalPointsResponse.body.data.points;
      expect(finalPoints).toBe(initialPoints - item.price_points);

      const finalInventoryResponse = await request(app)
        .get('/api/store/inventory')
        .set('Authorization', `Bearer test-token-${testUser.id}`);

      const finalInventoryCount = finalInventoryResponse.body.data.length;
      expect(finalInventoryCount).toBe(initialInventoryCount);
    });
  });
});
